class Solution:
    def findRepeatedDnaSequences(self, s: str) -> List[str]:
        L, n = 10, len(s)
        seen, output = {}, []
        for i in range(n - L + 1):
            tmp = s[i:i + L]
            if tmp not in seen:
                seen[tmp] = 1
            else:
                if seen[tmp] == 1:
                    output.append(tmp)
                seen[tmp] += 1
        return output

